  1→"use client";
  2→
  3→import type {
  4→  DashboardGroup,
  5→  PanelDescriptor,
  6→} from "@/components/shared/dashboard/dashboard-model";
  7→import DashboardPage from "@/components/shared/dashboard/dashboard-page";
  8→import { Button } from "@/components/ui/button";
  9→import { Input } from "@/components/ui/input";
 10→import {
 11→  DropdownMenu,
 12→  DropdownMenuContent,
 13→  DropdownMenuItem,
 14→  DropdownMenuTrigger,
 15→} from "@/components/ui/dropdown-menu";
 16→import {
 17→  Check,
 18→  Edit2,
 19→  Pencil,
 20→  Plus,
 21→  Trash2,
 22→  X,
 23→} from "lucide-react";
 24→import { memo, useCallback, useEffect, useMemo, useState } from "react";
 25→import {
 26→  CustomDashboardStorage,
 27→  type CustomDashboardConfig,
 28→} from "./custom-dashboard-storage";
 29→import { PanelConfigDialog } from "./panel-config-dialog";
 30→import { TabManager } from "@/components/tab-manager";
 31→import {
 32→  CustomDashboardContext,
 33→  type CustomDashboardPanelActions,
 34→} from "./custom-dashboard-context";
 35→
 36→interface CustomDashboardTabProps {
 37→  dashboardId: string;
 38→  dashboardName?: string;
 39→}
 40→
 41→const CustomDashboardTabComponent = ({
 42→  dashboardId,
 43→  dashboardName,
 44→}: CustomDashboardTabProps) => {
 45→  const storage = CustomDashboardStorage.getInstance();
 46→
 47→  // Load dashboard config from storage
 48→  const [config, setConfig] = useState<CustomDashboardConfig | null>(null);
 49→  const [isEditing, setIsEditing] = useState(false);
 50→  const [editingName, setEditingName] = useState("");
 51→  const [showPanelDialog, setShowPanelDialog] = useState(false);
 52→  const [editingPanel, setEditingPanel] = useState<PanelDescriptor | null>(null);
 53→  const [editingPanelIndex, setEditingPanelIndex] = useState<number>(-1);
 54→
 55→  // Track the rendered dashboard key to force re-render after edits
 56→  const [dashboardKey, setDashboardKey] = useState(0);
 57→
 58→
 59→  // Load from storage on mount
 60→  useEffect(() => {
 61→    const loaded = storage.get(dashboardId);
 62→    if (loaded) {
 63→      setConfig(loaded);
 64→      setEditingName(loaded.name);
 65→    } else {
 66→      // Dashboard not found - create a new one
 67→      const newConfig = storage.createNew(dashboardName ?? "Untitled Dashboard");
 68→      // Update the ID to match
 69→      newConfig.id = dashboardId;
 70→      storage.save(newConfig);
 71→      setConfig(newConfig);
 72→      setEditingName(newConfig.name);
 73→      setIsEditing(true);
 74→    }
 75→  }, [dashboardId, dashboardName, storage]);
 76→
 77→  // Save config to storage (forces dashboard re-render for structural changes)
 78→  const saveConfig = useCallback(
 79→    (updatedConfig: CustomDashboardConfig) => {
 80→      storage.save(updatedConfig);
 81→      setConfig(updatedConfig);
 82→      setDashboardKey((k) => k + 1);
 83→    },
 84→    [storage]
 85→  );
 86→
 87→  // Handle name edit
 88→  const handleSaveName = useCallback(() => {
 89→    if (!config) return;
 90→    const trimmed = editingName.trim();
 91→    if (!trimmed) return;
 92→    const updated = { ...config, name: trimmed };
 93→    saveConfig(updated);
 94→    setIsEditing(false);
 95→
 96→    // Update tab title
 97→    TabManager.updateTabTitle(
 98→      `custom-dashboard:${dashboardId}`,
 99→      trimmed
100→    );
101→  }, [config, editingName, saveConfig, dashboardId]);
102→
103→  // Add panel to the first available section
104→  const handleAddPanel = useCallback(
105→    (panel: PanelDescriptor) => {
106→      if (!config) return;
107→
108→      if (editingPanelIndex >= 0) {
109→        // Update existing panel - need to find it in the correct section
110→        const updatedPanels = updatePanelAtFlatIndex(config.panels, editingPanelIndex, panel);
111→        saveConfig({ ...config, panels: updatedPanels });
112→      } else {
113→        // Add new panel to the first section
114→        const updatedPanels = addPanelToFirstSection(config.panels, panel);
115→        saveConfig({ ...config, panels: updatedPanels });
116→      }
117→      setEditingPanel(null);
118→      setEditingPanelIndex(-1);
119→    },
120→    [config, editingPanelIndex, saveConfig]
121→  );
122→
123→  // Edit panel
124→  const handleEditPanel = useCallback(
125→    (index: number) => {
126→      if (!config) return;
127→      const panels = flattenPanels(config.panels);
128→      if (index >= 0 && index < panels.length) {
129→        setEditingPanel(panels[index]);
130→        setEditingPanelIndex(index);
131→        setShowPanelDialog(true);
132→      }
133→    },
134→    [config]
135→  );
136→
137→  // Delete panel by flat index
138→  const handleDeletePanel = useCallback(
139→    (index: number) => {
140→      if (!config) return;
141→      const updatedPanels = deletePanelAtFlatIndex(config.panels, index);
142→      saveConfig({ ...config, panels: updatedPanels });
143→    },
144→    [config, saveConfig]
145→  );
146→
147→  // Build Dashboard model for rendering
148→  const dashboard = useMemo(() => {
149→    if (!config) return null;
150→    return CustomDashboardStorage.toDashboard(config);
151→  }, [config, dashboardKey]);
152→
153→  const allPanels = useMemo(
154→    () => (config ? flattenPanels(config.panels) : []),
155→    [config]
156→  );
157→
158→  // Context value for per-widget edit/delete actions
159→  const panelActions = useMemo<CustomDashboardPanelActions>(
160→    () => ({
161→      onEditPanel: handleEditPanel,
162→      onDeletePanel: handleDeletePanel,
163→      getPanelIndex: (descriptor) => {
164→        return allPanels.findIndex((p) => p === descriptor);
165→      },
166→    }),
167→    [handleEditPanel, handleDeletePanel, allPanels]
168→  );
169→
170→  if (!config || !dashboard) {
171→    return (
172→      <div className="flex items-center justify-center h-full text-muted-foreground">
173→        Loading dashboard...
174→      </div>
175→    );
176→  }
177→
178→  const hasPanels = allPanels.length > 0;
179→
180→  return (
181→    <div className="flex flex-col h-full w-full overflow-hidden">
182→      {/* Toolbar */}
183→      <div className="flex items-center gap-2 px-3 py-2 border-b bg-background shrink-0">
184→        {/* Dashboard name */}
185→        {isEditing ? (
186→          <div className="flex items-center gap-1">
187→            <Input
188→              value={editingName}
189→              onChange={(e) => setEditingName(e.target.value)}
190→              className="h-7 w-48 text-sm"
191→              autoFocus
192→              onKeyDown={(e) => {
193→                if (e.key === "Enter") handleSaveName();
194→                if (e.key === "Escape") {
195→                  setEditingName(config.name);
196→                  setIsEditing(false);
197→                }
198→              }}
199→            />
200→            <Button variant="ghost" size="icon" className="h-7 w-7" onClick={handleSaveName}>
201→              <Check className="h-3.5 w-3.5" />
202→            </Button>
203→            <Button
204→              variant="ghost"
205→              size="icon"
206→              className="h-7 w-7"
207→              onClick={() => {
208→                setEditingName(config.name);
209→                setIsEditing(false);
210→              }}
211→            >
212→              <X className="h-3.5 w-3.5" />
213→            </Button>
214→          </div>
215→        ) : (
216→          <button
217→            className="flex items-center gap-1.5 text-sm font-medium hover:bg-muted/50 px-2 py-1 rounded transition-colors"
218→            onClick={() => setIsEditing(true)}
219→          >
220→            {config.name}
221→            <Pencil className="h-3 w-3 text-muted-foreground" />
222→          </button>
223→        )}
224→
225→        <div className="flex-1" />
226→
227→        {/* Add panel */}
228→        <Button
229→          variant="outline"
230→          size="sm"
231→          className="h-7 text-xs gap-1"
232→          onClick={() => {
233→            setEditingPanel(null);
234→            setEditingPanelIndex(-1);
235→            setShowPanelDialog(true);
236→          }}
237→        >
238→          <Plus className="h-3.5 w-3.5" />
239→          Add Panel
240→        </Button>
241→      </div>
242→
243→      {/* Dashboard content */}
244→      <div className="flex-1 min-h-0 overflow-hidden">
245→        <CustomDashboardContext.Provider value={panelActions}>
246→          {hasPanels ? (
247→            <DashboardPage
248→              dashboardId={`custom-dashboard-${dashboardKey}`}
249→              key={dashboardKey}
250→              panels={dashboard}
251→              showTimeSpanSelector={config.filter.showTimeSpanSelector}
252→              showRefresh={config.filter.showRefresh}
253→              headerActions={
254→                <PanelEditOverlay
255→                  panels={allPanels}
256→                  onEditPanel={handleEditPanel}
257→                  onDeletePanel={handleDeletePanel}
258→                />
259→              }
260→            />
261→          ) : (
262→            <EmptyDashboardState
263→              onAddPanel={() => {
264→                setEditingPanel(null);
265→                setEditingPanelIndex(-1);
266→                setShowPanelDialog(true);
267→              }}
268→            />
269→          )}
270→        </CustomDashboardContext.Provider>
271→      </div>
272→
273→      {/* Dialogs */}
274→      <PanelConfigDialog
275→        open={showPanelDialog}
276→        onOpenChange={setShowPanelDialog}
277→        onSave={handleAddPanel}
278→        editingPanel={editingPanel}
279→      />
280→
281→    </div>
282→  );
283→};
284→
285→/**
286→ * Empty state when no panels are added yet
287→ */
288→function EmptyDashboardState({ onAddPanel }: { onAddPanel: () => void }) {
289→  return (
290→    <div className="h-full flex flex-col items-center justify-center text-center p-8">
291→      <div className="text-muted-foreground mb-4">
292→        <svg className="h-16 w-16 mx-auto mb-4 opacity-30" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
293→          <rect x="3" y="3" width="7" height="7" rx="1" />
294→          <rect x="14" y="3" width="7" height="7" rx="1" />
295→          <rect x="3" y="14" width="7" height="7" rx="1" />
296→          <rect x="14" y="14" width="7" height="7" rx="1" />
297→        </svg>
298→        <p className="text-sm">No panels yet. Add a panel to get started.</p>
299→      </div>
300→      <Button onClick={onAddPanel} className="gap-2">
301→        <Plus className="h-4 w-4" />
302→        Add Your First Panel
303→      </Button>
304→    </div>
305→  );
306→}
307→
308→/**
309→ * Overlay buttons that appear in the dashboard header for editing panels
310→ */
311→function PanelEditOverlay({
312→  panels,
313→  onEditPanel,
314→  onDeletePanel,
315→}: {
316→  panels: PanelDescriptor[];
317→  onEditPanel: (index: number) => void;
318→  onDeletePanel: (index: number) => void;
319→}) {
320→  if (panels.length === 0) return null;
321→
322→  return (
323→    <DropdownMenu>
324→      <DropdownMenuTrigger asChild>
325→        <Button variant="outline" size="sm" className="h-7 text-xs gap-1">
326→          <Edit2 className="h-3.5 w-3.5" />
327→          Edit Panels
328→        </Button>
329→      </DropdownMenuTrigger>
330→      <DropdownMenuContent align="end" className="w-64">
331→        {panels.map((panel, index) => (
332→          <DropdownMenuItem
333→            key={index}
334→            className="flex items-center justify-between"
335→            onSelect={(e) => e.preventDefault()}
336→          >
337→            <span className="text-sm truncate mr-2">
338→              {panel.titleOption?.title ?? `Panel ${index + 1}`}
339→            </span>
340→            <div className="flex items-center gap-1 shrink-0">
341→              <Button
342→                variant="ghost"
343→                size="icon"
344→                className="h-6 w-6"
345→                onClick={() => onEditPanel(index)}
346→              >
347→                <Pencil className="h-3 w-3" />
348→              </Button>
349→              <Button
350→                variant="ghost"
351→                size="icon"
352→                className="h-6 w-6 text-destructive hover:text-destructive"
353→                onClick={() => onDeletePanel(index)}
354→              >
355→                <Trash2 className="h-3 w-3" />
356→              </Button>
357→            </div>
358→          </DropdownMenuItem>
359→        ))}
360→      </DropdownMenuContent>
361→    </DropdownMenu>
362→  );
363→}
364→
365→/**
366→ * Check if an item is a DashboardGroup
367→ */
368→function isDashboardGroup(item: PanelDescriptor | DashboardGroup): item is DashboardGroup {
369→  return "charts" in item && Array.isArray((item as DashboardGroup).charts);
370→}
371→
372→/**
373→ * Flatten panels from dashboard config (handles groups)
374→ */
375→function flattenPanels(
376→  panels: (PanelDescriptor | DashboardGroup)[]
377→): PanelDescriptor[] {
378→  const result: PanelDescriptor[] = [];
379→  for (const item of panels) {
380→    if (isDashboardGroup(item)) {
381→      result.push(...item.charts);
382→    } else {
383→      result.push(item);
384→    }
385→  }
386→  return result;
387→}
388→
389→/**
390→ * Add a panel to the first section (DashboardGroup).
391→ * If no section exists, creates a default one.
392→ */
393→function addPanelToFirstSection(
394→  panels: (PanelDescriptor | DashboardGroup)[],
395→  newPanel: PanelDescriptor
396→): (PanelDescriptor | DashboardGroup)[] {
397→  const updatedPanels = [...panels];
398→
399→  // Find the first DashboardGroup
400→  const firstGroupIndex = updatedPanels.findIndex(isDashboardGroup);
401→
402→  if (firstGroupIndex >= 0) {
403→    // Add to existing first group
404→    const group = updatedPanels[firstGroupIndex] as DashboardGroup;
405→    updatedPanels[firstGroupIndex] = {
406→      ...group,
407→      charts: [...group.charts, newPanel],
408→    };
409→  } else {
410→    // No groups exist - create a default section with this panel
411→    const defaultSection: DashboardGroup = {
412→      title: "Default",
413→      charts: [newPanel],
414→      collapsed: false,
415→    };
416→    updatedPanels.push(defaultSection);
417→  }
418→
419→  return updatedPanels;
420→}
421→
422→/**
423→ * Update a panel at a flat index (accounting for sections)
424→ */
425→function updatePanelAtFlatIndex(
426→  panels: (PanelDescriptor | DashboardGroup)[],
427→  flatIndex: number,
428→  updatedPanel: PanelDescriptor
429→): (PanelDescriptor | DashboardGroup)[] {
430→  const result: (PanelDescriptor | DashboardGroup)[] = [];
431→  let currentFlatIndex = 0;
432→
433→  for (const item of panels) {
434→    if (isDashboardGroup(item)) {
435→      const groupCharts = [...item.charts];
436→      let foundInGroup = false;
437→
438→      for (let i = 0; i < groupCharts.length; i++) {
439→        if (currentFlatIndex === flatIndex) {
440→          groupCharts[i] = updatedPanel;
441→          foundInGroup = true;
442→        }
443→        currentFlatIndex++;
444→      }
445→
446→      result.push(foundInGroup ? { ...item, charts: groupCharts } : item);
447→    } else {
448→      if (currentFlatIndex === flatIndex) {
449→        result.push(updatedPanel);
450→      } else {
451→        result.push(item);
452→      }
453→      currentFlatIndex++;
454→    }
455→  }
456→
457→  return result;
458→}
459→
460→/**
461→ * Delete a panel at a flat index (accounting for sections)
462→ */
463→function deletePanelAtFlatIndex(
464→  panels: (PanelDescriptor | DashboardGroup)[],
465→  flatIndex: number
466→): (PanelDescriptor | DashboardGroup)[] {
467→  const result: (PanelDescriptor | DashboardGroup)[] = [];
468→  let currentFlatIndex = 0;
469→
470→  for (const item of panels) {
471→    if (isDashboardGroup(item)) {
472→      const groupCharts: PanelDescriptor[] = [];
473→
474→      for (const chart of item.charts) {
475→        if (currentFlatIndex !== flatIndex) {
476→          groupCharts.push(chart);
477→        }
478→        currentFlatIndex++;
479→      }
480→
481→      // Keep the group even if empty (user can delete section explicitly)
482→      result.push({ ...item, charts: groupCharts });
483→    } else {
484→      if (currentFlatIndex !== flatIndex) {
485→        result.push(item);
486→      }
487→      currentFlatIndex++;
488→    }
489→  }
490→
491→  return result;
492→}
