  1→import { useConnection } from "@/components/connection/connection-context";
  2→import { DashboardGroupSection } from "@/components/shared/dashboard/dashboard-group-section";
  3→import type {
  4→  Dashboard,
  5→  DashboardGroup,
  6→  TimeseriesDescriptor,
  7→} from "@/components/shared/dashboard/dashboard-model";
  8→import DashboardPage from "@/components/shared/dashboard/dashboard-page";
  9→import { ThemedSyntaxHighlighter } from "@/components/shared/themed-syntax-highlighter";
 10→import { Dialog } from "@/components/shared/use-dialog";
 11→import { Button } from "@/components/ui/button";
 12→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
 13→import { type QueryResponse } from "@/lib/connection/connection";
 14→import { AlertTriangle, EllipsisVertical } from "lucide-react";
 15→import { memo, useCallback, useEffect, useRef, useState } from "react";
 16→
 17→interface DashboardRow {
 18→  dashboard: string;
 19→  title: string;
 20→  query: string;
 21→}
 22→
 23→interface SkippedDashboard {
 24→  dashboard: string;
 25→  title: string;
 26→  query: string;
 27→  reason: string;
 28→}
 29→
 30→interface DashboardsProps {
 31→  database: string;
 32→  table: string;
 33→}
 34→
 35→export const Dashboards = memo(({ database, table }: DashboardsProps) => {
 36→  const { connection } = useConnection();
 37→  const [dashboard, setDashboard] = useState<Dashboard>({
 38→    version: 3,
 39→    filter: {},
 40→    charts: [],
 41→  });
 42→  const [error, setError] = useState<string | null>(null);
 43→  const [skippedDashboards, setSkippedDashboards] = useState<SkippedDashboard[]>([]);
 44→  const previousConnectionRef = useRef<string | null>(null);
 45→
 46→  const fetchDashboards = useCallback(
 47→    (hasMetricLogTable: boolean, hasAsynchronousMetricLogTable: boolean) => {
 48→      // Fetch dashboard definitions from system.dashboards (without predefined dashboard)
 49→      if (!connection) return;
 50→
 51→      connection
 52→        .query(
 53→          "SELECT dashboard, title, query FROM system.dashboards ORDER BY dashboard, title",
 54→          {
 55→            default_format: "JSON",
 56→            output_format_json_quote_64bit_integers: 0,
 57→          },
 58→          {
 59→            "Content-Type": "text/plain",
 60→          }
 61→        )
 62→        .response.then((response: QueryResponse) => {
 63→          try {
 64→            const responseData = response.data.json<any>();
 65→            const rows = responseData.data || [];
 66→            const meta = responseData.meta || [];
 67→
 68→            // Build column map
 69→            const columnMap = new Map<string, number>();
 70→            meta.forEach((colMeta: { name: string }, index: number) => {
 71→              columnMap.set(colMeta.name, index);
 72→            });
 73→
 74→            // Group rows by dashboard category
 75→            const dashboardMap = new Map<string, DashboardRow[]>();
 76→
 77→            // Check if rows are arrays or objects
 78→            const firstRow = rows[0];
 79→            const isArrayFormat = Array.isArray(firstRow);
 80→
 81→            rows.forEach((row: unknown) => {
 82→              let dashboardName: string;
 83→              let title: string;
 84→              let query: string;
 85→
 86→              if (isArrayFormat) {
 87→                // Array format: row is [value1, value2, ...]
 88→                const rowArray = row as unknown[];
 89→                const dashboardIndex = columnMap.get("dashboard");
 90→                const titleIndex = columnMap.get("title");
 91→                const queryIndex = columnMap.get("query");
 92→
 93→                if (
 94→                  dashboardIndex === undefined ||
 95→                  titleIndex === undefined ||
 96→                  queryIndex === undefined
 97→                ) {
 98→                  return;
 99→                }
100→
101→                dashboardName = String(rowArray[dashboardIndex] ?? "");
102→                title = String(rowArray[titleIndex] ?? "");
103→                query = String(rowArray[queryIndex] ?? "");
104→              } else {
105→                // Object format: row is {column1: value1, column2: value2, ...}
106→                const rowObject = row as Record<string, unknown>;
107→                dashboardName = String(rowObject["dashboard"] ?? "");
108→                title = String(rowObject["title"] ?? "");
109→                query = String(rowObject["query"] ?? "");
110→              }
111→
112→              // Validate extracted values
113→              if (!dashboardName || dashboardName === "undefined" || !title || !query) {
114→                return;
115→              }
116→
117→              if (!dashboardMap.has(dashboardName)) {
118→                dashboardMap.set(dashboardName, []);
119→              }
120→              dashboardMap.get(dashboardName)!.push({ dashboard: dashboardName, title, query });
121→            });
122→
123→            // Convert each row to a timeseries chart, grouped by dashboard name
124→            const dashboardGroups: DashboardGroup[] = [];
125→            const skipped: SkippedDashboard[] = [];
126→
127→            dashboardMap.forEach((dashboardRows, dashboardName) => {
128→              const groupCharts: TimeseriesDescriptor[] = [];
129→
130→              dashboardRows.forEach((row, index) => {
131→                // Validate row data
132→                if (!row.title || !row.query) {
133→                  return;
134→                }
135→
136→                // Check if query references metric_log or asynchronous_metric_log
137→                const queryLower = row.query.toLowerCase();
138→                const referencesMetricLog =
139→                  queryLower.includes("metric_log") &&
140→                  !queryLower.includes("asynchronous_metric_log");
141→                const referencesAsynchronousMetricLog =
142→                  queryLower.includes("asynchronous_metric_log");
143→
144→                // Skip if query references metric_log but table doesn't exist
145→                if (referencesMetricLog && !hasMetricLogTable) {
146→                  skipped.push({
147→                    dashboard: row.dashboard,
148→                    title: row.title,
149→                    query: row.query,
150→                    reason: "metric_log table not available",
151→                  });
152→                  return;
153→                }
154→
155→                // Skip if query references asynchronous_metric_log but table doesn't exist
156→                if (referencesAsynchronousMetricLog && !hasAsynchronousMetricLogTable) {
157→                  skipped.push({
158→                    dashboard: row.dashboard,
159→                    title: row.title,
160→                    query: row.query,
161→                    reason: "asynchronous_metric_log table not available",
162→                  });
163→                  return;
164→                }
165→
166→                const chartTitle = row.title || `Chart ${index}`;
167→
168→                groupCharts.push({
169→                  type: "line" as const,
170→                  titleOption: {
171→                    title: chartTitle,
172→                  },
173→                  gridPos: { w: 6, h: 6 }, // Default size for charts
174→                  collapsed: false,
175→                  yAxis: [{}], // Default y-axis
176→                  datasource: {
177→                    sql: row.query,
178→                  },
179→                });
180→              });
181→
182→              // Create a group for this dashboard name if it has charts
183→              if (groupCharts.length > 0) {
184→                dashboardGroups.push({
185→                  title: dashboardName,
186→                  charts: groupCharts,
187→                  collapsed: true,
188→                });
189→              }
190→            });
191→
192→            // Track skipped dashboards in state for separate rendering
193→            setSkippedDashboards(skipped);
194→
195→            const mergedDashboard: Dashboard = {
196→              name: "dashboard",
197→              version: 3,
198→              filter: {},
199→              charts: dashboardGroups,
200→            };
201→
202→            setDashboard(mergedDashboard);
203→            setError(null);
204→          } catch (err) {
205→            console.error("Error processing dashboard data:", err);
206→            setError(null);
207→          }
208→        })
209→        .catch((error) => {
210→          console.error("Error fetching dashboard data:", error);
211→          setError(null);
212→        });
213→    },
214→    [connection]
215→  );
216→
217→  useEffect(() => {
218→    if (!connection) {
219→      return;
220→    }
221→
222→    // Skip if connection hasn't changed
223→    const connectionId = connection.name;
224→    if (previousConnectionRef.current === connectionId) {
225→      return;
226→    }
227→    previousConnectionRef.current = connectionId;
228→
229→    // First, check if metric_log and asynchronous_metric_log tables exist
230→    connection
231→      .query(
232→        `SELECT name FROM system.tables WHERE database = 'system' AND (name LIKE 'metric_log%' OR name LIKE 'asynchronous_metric_log%')`,
233→        {
234→          default_format: "JSON",
235→          output_format_json_quote_64bit_integers: 0,
236→        },
237→        {
238→          "Content-Type": "text/plain",
239→        }
240→      )
241→      .response.then((response: QueryResponse) => {
242→        try {
243→          const responseData = response.data.json<any>();
244→          const rows = responseData.data || [];
245→          const meta = responseData.meta || [];
246→
247→          // Build column map
248→          const columnMap = new Map<string, number>();
249→          meta.forEach((colMeta: { name: string }, index: number) => {
250→            columnMap.set(colMeta.name, index);
251→          });
252→
253→          // Check row format
254→          const firstRow = rows[0];
255→          const isArrayFormat = Array.isArray(firstRow);
256→
257→          let hasMetricLogTable = false;
258→          let hasAsynchronousMetricLogTable = false;
259→
260→          rows.forEach((row: unknown) => {
261→            let tableName: string;
262→
263→            if (isArrayFormat) {
264→              const rowArray = row as unknown[];
265→              const nameIndex = columnMap.get("name");
266→              if (nameIndex !== undefined) {
267→                tableName = String(rowArray[nameIndex] ?? "");
268→              } else {
269→                return;
270→              }
271→            } else {
272→              const rowObject = row as Record<string, unknown>;
273→              tableName = String(rowObject["name"] ?? "");
274→            }
275→
276→            if (tableName.startsWith("metric_log")) {
277→              hasMetricLogTable = true;
278→            }
279→            if (tableName.startsWith("asynchronous_metric_log")) {
280→              hasAsynchronousMetricLogTable = true;
281→            }
282→          });
283→
284→          // Now fetch dashboard definitions
285→          fetchDashboards(hasMetricLogTable, hasAsynchronousMetricLogTable);
286→        } catch (err) {
287→          console.error("Error checking metric_log tables:", err);
288→          // Continue with fetching dashboards anyway
289→          fetchDashboards(false, false);
290→        }
291→      })
292→      .catch((error) => {
293→        console.error("Error checking metric_log tables:", error);
294→        // Continue with fetching dashboards anyway
295→        fetchDashboards(false, false);
296→      });
297→  }, [connection, fetchDashboards, database, table]);
298→
299→  const headerActions = null;
300→
301→  if (error) {
302→    return (
303→      <div className="px-2 pt-2">
304→        <div className="flex items-center justify-center h-screen">
305→          <div className="text-destructive">
306→            <p className="font-semibold">Error loading dashboard:</p>
307→            <p className="text-sm">{error}</p>
308→          </div>
309→        </div>
310→      </div>
311→    );
312→  }
313→
314→  return (
315→    <div className="flex flex-col px-2" style={{ height: "calc(100vh - 49px)" }}>
316→      <DashboardPage dashboardId="system-dashboards" panels={dashboard} headerActions={headerActions}>
