  3→import { Button } from "@/components/ui/button";
  4→import { Input } from "@/components/ui/input";
  5→import { TabManager } from "@/components/tab-manager";
  6→import { LayoutDashboard, Plus, Trash2 } from "lucide-react";
  7→import { memo, useCallback, useState } from "react";
  8→import {
  9→  CustomDashboardStorage,
 10→  type CustomDashboardConfig,
 11→} from "./custom-dashboard-storage";
 12→
 13→interface CustomDashboardListProps {
 14→  onClose?: () => void;
 15→}
 16→
 17→/**
 18→ * A list of all saved custom dashboards with create/open/delete actions.
 19→ * Used inside the sidebar hover card or popover.
 20→ */
 21→const CustomDashboardListComponent = ({ onClose }: CustomDashboardListProps) => {
 22→  const storage = CustomDashboardStorage.getInstance();
 23→  const [dashboards, setDashboards] = useState<CustomDashboardConfig[]>(() =>
 24→    storage.getAll()
 25→  );
 26→  const [showCreate, setShowCreate] = useState(false);
 27→  const [newName, setNewName] = useState("");
 28→
 29→  const refreshList = useCallback(() => {
 30→    setDashboards(storage.getAll());
 31→  }, [storage]);
 32→
 33→  const handleCreate = useCallback(() => {
 34→    const name = newName.trim() || "Untitled Dashboard";
 35→    const config = storage.createNew(name);
 36→    setNewName("");
 37→    setShowCreate(false);
 38→    refreshList();
 39→
 40→    // Open the new dashboard in a tab
 41→    TabManager.openTab({
 42→      id: `custom-dashboard:${config.id}`,
 43→      type: "custom-dashboard",
 44→      dashboardId: config.id,
 45→      dashboardName: config.name,
 46→    });
 47→    onClose?.();
 48→  }, [newName, storage, refreshList, onClose]);
 49→
 50→  const handleOpen = useCallback(
 51→    (config: CustomDashboardConfig) => {
 52→      TabManager.openTab({
 53→        id: `custom-dashboard:${config.id}`,
 54→        type: "custom-dashboard",
 55→        dashboardId: config.id,
 56→        dashboardName: config.name,
 57→      });
 58→      onClose?.();
 59→    },
 60→    [onClose]
 61→  );
 62→
 63→  const handleDelete = useCallback(
 64→    (id: string, e: React.MouseEvent) => {
 65→      e.stopPropagation();
 66→      storage.delete(id);
 67→      refreshList();
 68→    },
 69→    [storage, refreshList]
 70→  );
 71→
 72→  return (
 73→    <div className="space-y-2">
 74→      {/* Create new */}
 75→      {showCreate ? (
 76→        <div className="flex items-center gap-1">
 77→          <Input
 78→            value={newName}
 79→            onChange={(e) => setNewName(e.target.value)}
 80→            placeholder="Dashboard name"
 81→            className="h-7 text-sm flex-1"
 82→            autoFocus
 83→            onKeyDown={(e) => {
 84→              if (e.key === "Enter") handleCreate();
 85→              if (e.key === "Escape") setShowCreate(false);
 86→            }}
 87→          />
 88→          <Button variant="ghost" size="sm" className="h-7 px-2" onClick={handleCreate}>
 89→            <Plus className="h-3.5 w-3.5" />
 90→          </Button>
 91→        </div>
 92→      ) : (
 93→        <button
 94→          className="w-full flex items-center gap-2 px-2 py-1.5 text-sm rounded-sm hover:bg-accent hover:text-accent-foreground cursor-pointer transition-colors text-primary"
 95→          onClick={() => setShowCreate(true)}
 96→        >
 97→          <Plus className="h-4 w-4" />
 98→          New Dashboard
 99→        </button>
100→      )}
101→
102→      {/* Dashboard list */}
103→      {dashboards.length === 0 && !showCreate && (
104→        <p className="text-xs text-muted-foreground px-2 py-1">
105→          No custom dashboards yet
106→        </p>
107→      )}
108→
109→      {dashboards.map((db) => (
110→        <div
111→          key={db.id}
112→          className="w-full flex items-center gap-2 px-2 py-1.5 text-sm rounded-sm hover:bg-accent hover:text-accent-foreground cursor-pointer transition-colors group"
113→          onClick={() => handleOpen(db)}
114→        >
115→          <LayoutDashboard className="h-4 w-4 shrink-0" />
116→          <span className="truncate flex-1 text-left">{db.name}</span>
117→          <button
118→            className="opacity-0 group-hover:opacity-100 hover:text-destructive transition-opacity shrink-0"
119→            onClick={(e) => handleDelete(db.id, e)}
120→          >
121→            <Trash2 className="h-3.5 w-3.5" />
122→          </button>
123→        </div>
124→      ))}
125→    </div>
126→  );
127→};
