140→function DashboardFilterWithReset({
141→  filterRef,
142→  filterSpecs,
143→  onFilterChange,
144→  onTimeSpanChange,
145→  onLoadSourceData,
146→  timezone,
147→  showTimeSpanSelector,
148→  showRefresh,
149→  showAutoRefresh,
150→  headerActions,
151→  showResetLayout = true,
152→}: DashboardFilterWithResetProps) {
153→  const { resetLayout } = useDashboardLayout();
154→
155→  return (
156→    <DashboardFilterComponent
157→      ref={filterRef}
158→      filterSpecs={filterSpecs}
159→      onFilterChange={onFilterChange}
160→      onTimeSpanChange={onTimeSpanChange}
161→      onLoadSourceData={onLoadSourceData}
162→      timezone={timezone}
163→      showTimeSpanSelector={showTimeSpanSelector}
164→      showRefresh={showRefresh}
165→      showAutoRefresh={showAutoRefresh}
166→      onResetLayout={showResetLayout ? resetLayout : undefined}
167→    >
