172→
173→const DashboardPage = forwardRef<DashboardPageRef, DashboardPageProps>(
174→  (
175→    {
176→      panels,
177→      filterSpecs,
178→      showInputFilter = false,
179→      headerActions,
180→      timezone = "UTC",
181→      showTimeSpanSelector = true,
182→      showRefresh = true,
183→      showAutoRefresh = false,
184→      chartSelectionFilterName,
185→      dashboardId,
186→      children,
187→      showSectionEditControls,
188→      onSectionRename,
189→      onSectionDelete,
190→      onSectionCollapseChange,
191→    },
192→    ref
193→  ) => {
194→    const { connection } = useConnection();
195→
196→    // Generate default layouts for the layout provider
197→    const defaultLayouts = useMemo(() => generateDefaultLayouts(panels), [panels]);
198→
199→    const inputFilterRef = useRef<HTMLInputElement>(null);
200→    const filterRef = useRef<DashboardFilterComponent>(null);
201→    const panelsRef = useRef<DashboardPanelContainerRef>(null);
202→
203→    useImperativeHandle(
204→      ref,
205→      () => ({
206→        setSelectedTimeSpan: (timeSpan: TimeSpan) => {
207→          filterRef.current?.setSelectedTimeSpan(timeSpan);
208→        },
209→        setFilter: (filterName: string, value: string) => {
210→          filterRef.current?.setFilter(filterName, value);
211→        },
212→      }),
213→      []
214→    );
215→
216→    const defaultLoadFilterData = useCallback(
217→      async (query: SQLQuery) => {
218→        if (!connection) return [];
219→        try {
220→          // Cluster template replacement is now handled by connection.queryOnNode()
221→          const sql = query.sql;
222→
223→          const { response } = connection.queryOnNode(sql, {
224→            default_format: "JSONCompact",
225→            ...query.params,
226→          });
227→
228→          const apiResponse = await response;
229→          return apiResponse.data
230→            .json<JSONCompactFormatResponse>()
231→            .data.map((row: unknown[]) => String(row[0]));
232→        } catch (caught) {
233→          console.error(caught);
234→          return [];
235→        }
236→      },
237→      [connection]
238→    );
239→
240→    const refreshPanels = useCallback(
241→      (timeSpan: TimeSpan, filter: SelectedFilter | undefined, inputFilter?: string) => {
242→        const parts: string[] = [];
243→        if (filter?.expr) {
244→          parts.push(filter.expr);
245→        }
246→        if (inputFilter !== undefined) {
247→          const value = inputFilter || inputFilterRef.current?.value || "";
248→          if (value) {
249→            parts.push(value);
250→          }
251→        } else {
252→          const value = inputFilterRef.current?.value || "";
253→          if (value) {
254→            parts.push(value);
255→          }
256→        }
257→        const filterExpression = parts.length > 0 ? parts.join(" AND ") : "1=1";
258→        panelsRef.current?.refresh(timeSpan, filterExpression);
259→      },
260→      []
261→    );
262→
263→    useEffect(() => {
264→      const timer = setTimeout(() => {
265→        if (filterRef.current) {
266→          const timeSpan = filterRef.current.getSelectedTimeSpan();
267→          const filter = filterRef.current.getSelectedFilter();
268→          refreshPanels(timeSpan, filter);
269→        }
270→      }, 0);
271→
272→      return () => clearTimeout(timer);
273→    }, [refreshPanels]);
274→
275→    const handleSelectionFilterChange = useCallback(
276→      (filter: SelectedFilter) => {
277→        const timeSpan = filterRef.current?.getSelectedTimeSpan();
278→        if (!timeSpan) {
279→          return;
280→        }
281→        refreshPanels(timeSpan, filter);
282→      },
283→      [refreshPanels]
284→    );
285→
286→    const handleTimeSpanChange = useCallback(
287→      (timeSpan: TimeSpan) => {
288→        const filter = filterRef.current?.getSelectedFilter();
289→        refreshPanels(timeSpan, filter);
290→      },
291→      [refreshPanels]
292→    );
293→
294→    const handleInputFilterKeyDown = useCallback(
295→      (event: React.KeyboardEvent<HTMLInputElement>) => {
296→        if (event.key === "Enter") {
297→          const inputFilterValue = inputFilterRef.current?.value || "";
298→          const timeSpan = filterRef.current?.getSelectedTimeSpan();
299→          const filter = filterRef.current?.getSelectedFilter();
300→          if (timeSpan) {
301→            refreshPanels(timeSpan, filter, inputFilterValue);
302→          }
303→        }
304→      },
305→      [refreshPanels]
306→    );
307→
308→    const handleChartSelection = useCallback(
309→      (timeSpan: TimeSpan, selection: { name: string; series: string; value: number }) => {
310→        filterRef.current?.setSelectedTimeSpan(timeSpan);
311→        if (chartSelectionFilterName && selection.series) {
312→          filterRef.current?.setFilter(chartSelectionFilterName, selection.series);
313→        }
314→      },
315→      [chartSelectionFilterName]
316→    );
317→
318→    const hasFilters = filterSpecs && filterSpecs.length > 0;
319→
320→    const dashboardContent = (
321→      <div className="flex flex-col h-full w-full overflow-hidden p-2 gap-2">
322→        {dashboardId ? (
323→          // With layout provider - use DashboardFilterWithReset for reset button
324→          <DashboardFilterWithReset
325→            filterRef={filterRef}
326→            filterSpecs={hasFilters ? filterSpecs : []}
327→            onFilterChange={hasFilters ? handleSelectionFilterChange : undefined}
328→            onTimeSpanChange={handleTimeSpanChange}
329→            onLoadSourceData={hasFilters ? defaultLoadFilterData : undefined}
330→            timezone={timezone}
331→            showTimeSpanSelector={showTimeSpanSelector}
332→            showRefresh={showRefresh}
333→            showAutoRefresh={showAutoRefresh}
334→            headerActions={headerActions}
335→          />
336→        ) : (
337→          // Without layout provider - regular filter without reset
338→          <DashboardFilterComponent
339→            ref={filterRef}
340→            filterSpecs={hasFilters ? filterSpecs : []}
341→            onFilterChange={hasFilters ? handleSelectionFilterChange : undefined}
342→            onTimeSpanChange={handleTimeSpanChange}
343→            onLoadSourceData={hasFilters ? defaultLoadFilterData : undefined}
344→            timezone={timezone}
345→            showTimeSpanSelector={showTimeSpanSelector}
346→            showRefresh={showRefresh}
347→            showAutoRefresh={showAutoRefresh}
348→          >
349→            {headerActions}
350→          </DashboardFilterComponent>
351→        )}
352→
353→        {showInputFilter && (
354→          <div className="relative">
355→            <Input
356→              ref={inputFilterRef}
357→              className="rounded-l rounded-r pl-2 h-8"
358→              placeholder="Input filter expression, press ENTER to apply"
359→              onKeyDown={handleInputFilterKeyDown}
360→            />
361→          </div>
362→        )}
363→
364→        <div className="flex-1 min-h-0 overflow-hidden">
365→          <DashboardPanelContainer
366→            ref={panelsRef}
367→            dashboard={panels}
368→            dashboardId={dashboardId}
369→            initialLoading={false}
370→            onChartSelection={chartSelectionFilterName ? handleChartSelection : undefined}
371→            showSectionEditControls={showSectionEditControls}
372→            onSectionRename={onSectionRename}
373→            onSectionDelete={onSectionDelete}
374→            onSectionCollapseChange={onSectionCollapseChange}
375→          >
376→            {children}
377→          </DashboardPanelContainer>
378→        </div>
379→      </div>
380→    );
381→
382→    // Wrap with layout provider if dashboardId is provided
383→    if (dashboardId) {
384→      return (
385→        <DashboardLayoutProvider dashboardId={dashboardId} defaultLayouts={defaultLayouts}>
386→          {dashboardContent}
387→        </DashboardLayoutProvider>
388→      );
389→    }
390→
391→    return dashboardContent;
392→  }
393→);
