 96→/**
 97→ * Event detail for active tab changes
 98→ */
 99→export interface ActiveTabChangeEventDetail {
100→  tabId: string;
101→  tabInfo: TabInfo | null; // null when tab is closed
102→}
103→
104→/**
105→ * Type-safe event listener for tab requests
106→ */
107→export type OpenTabEventHandler = (event: CustomEvent<TabInfo>) => void;
108→
109→/**
110→ * Type-safe event listener for active tab changes
111→ */
112→export type ActiveTabChangeEventHandler = (event: CustomEvent<ActiveTabChangeEventDetail>) => void;
113→
114→/**
115→ * Event detail for tab title updates
116→ */
117→export interface TabTitleUpdateEventDetail {
118→  tabId: string;
119→  title: string;
120→}
121→
122→/**
123→ * Type-safe event listener for tab title updates
124→ */
125→export type TabTitleUpdateEventHandler = (event: CustomEvent<TabTitleUpdateEventDetail>) => void;
126→
127→/**
128→ * Unified TabManager class for handling all tab events
129→ */
130→export class TabManager {
131→  private static readonly OPEN_TAB_EVENT = "OPEN_TAB";
132→
133→  // Queue to store events when no listener is active
134→  private static eventQueue: CustomEvent<TabInfo>[] = [];
135→  private static listenerCount = 0;
136→
137→  /**
138→   * Dispatch an event immediately or queue it if no listener is active
139→   */
140→  private static dispatchOrQueue(event: CustomEvent<TabInfo>): void {
141→    if (!isInBrowser()) {
142→      return;
143→    }
144→    if (TabManager.listenerCount > 0) {
145→      // Listener is active, dispatch immediately
146→      window.dispatchEvent(event);
147→    } else {
148→      // No listener yet, queue the event
149→      TabManager.eventQueue.push(event);
150→    }
151→  }
152→
153→  /**
154→   * Open a tab with the specified information
155→   */
156→  static openTab(tabInfo: TabInfo): void {
157→    if (!isInBrowser()) {
158→      return;
159→    }
160→    const event = new CustomEvent<TabInfo>(TabManager.OPEN_TAB_EVENT, { detail: tabInfo });
161→    TabManager.dispatchOrQueue(event);
162→  }
163→
164→  /**
165→   * Emit an activate query tab event (query tab is always present, this just activates it)
166→   */
167→  static activateQueryTab(options?: {
168→    query?: string;
169→    mode?: "replace" | "insert" | "none";
170→    execute?: boolean;
171→  }): void {
172→    // Query tab always has ID "query"
173→    TabManager.openTab({
174→      id: "query",
175→      type: "query",
176→      initialQuery: options?.query,
177→      initialMode: options?.mode,
178→      initialExecute: options?.execute,
179→    });
180→  }
181→
182→  /**
183→   * Add a listener for open tab events
184→   */
185→  static onOpenTab(handler: OpenTabEventHandler): () => void {
186→    if (!isInBrowser()) {
187→      return () => {};
188→    }
189→    const wrappedHandler = (e: Event) => {
190→      handler(e as CustomEvent<TabInfo>);
191→    };
192→
193→    window.addEventListener(TabManager.OPEN_TAB_EVENT, wrappedHandler);
194→    TabManager.listenerCount++;
195→
196→    // Replay any queued events (only if this is the first listener)
197→    if (TabManager.listenerCount === 1 && TabManager.eventQueue.length > 0) {
198→      const queuedEvents = [...TabManager.eventQueue];
199→      TabManager.eventQueue = []; // Clear the queue
200→
201→      // Dispatch queued events asynchronously to avoid blocking
202→      setTimeout(() => {
203→        for (const event of queuedEvents) {
204→          window.dispatchEvent(event);
205→        }
206→      }, 0);
207→    }
208→
209→    return () => {
210→      window.removeEventListener(TabManager.OPEN_TAB_EVENT, wrappedHandler);
211→      TabManager.listenerCount = Math.max(0, TabManager.listenerCount - 1);
212→    };
213→  }
214→
215→  private static readonly ACTIVE_TAB_CHANGE_EVENT = "ACTIVE_TAB_CHANGE";
216→  private static readonly CLOSE_TAB_EVENT = "CLOSE_TAB";
217→  private static readonly UPDATE_TAB_TITLE_EVENT = "UPDATE_TAB_TITLE";
218→
219→  /**
220→   * Emit an active tab change event
221→   */
222→  static sendActiveTabChange(tabId: string, tabInfo: TabInfo | null): void {
223→    if (!isInBrowser()) {
224→      return;
225→    }
226→    const event = new CustomEvent<ActiveTabChangeEventDetail>(TabManager.ACTIVE_TAB_CHANGE_EVENT, {
227→      detail: { tabId, tabInfo },
228→    });
229→    window.dispatchEvent(event);
230→  }
231→
232→  /**
233→   * Emit a close tab event
234→   */
235→  static closeTab(tabId: string): void {
236→    if (!isInBrowser()) {
237→      return;
238→    }
239→    const event = new CustomEvent<string>(TabManager.CLOSE_TAB_EVENT, {
240→      detail: tabId,
241→    });
242→    window.dispatchEvent(event);
243→  }
244→
245→  /**
246→   * Add a listener for close tab events
247→   */
248→  static onCloseTab(handler: (event: CustomEvent<string>) => void): () => void {
249→    if (!isInBrowser()) {
250→      return () => {};
251→    }
252→    const wrappedHandler = (e: Event) => {
253→      handler(e as CustomEvent<string>);
254→    };
255→    window.addEventListener(TabManager.CLOSE_TAB_EVENT, wrappedHandler);
256→    return () => window.removeEventListener(TabManager.CLOSE_TAB_EVENT, wrappedHandler);
257→  }
258→
259→  /**
260→   * Add a listener for active tab change events
261→   */
262→  static onActiveTabChange(handler: ActiveTabChangeEventHandler): () => void {
263→    if (!isInBrowser()) {
264→      return () => {};
265→    }
266→    const wrappedHandler = (e: Event) => {
267→      handler(e as CustomEvent<ActiveTabChangeEventDetail>);
268→    };
269→    window.addEventListener(TabManager.ACTIVE_TAB_CHANGE_EVENT, wrappedHandler);
270→    return () => window.removeEventListener(TabManager.ACTIVE_TAB_CHANGE_EVENT, wrappedHandler);
271→  }
272→
273→  /**
274→   * Update a tab's title
275→   */
276→  static updateTabTitle(tabId: string, title: string): void {
277→    if (!isInBrowser()) {
278→      return;
279→    }
280→    const event = new CustomEvent<TabTitleUpdateEventDetail>(TabManager.UPDATE_TAB_TITLE_EVENT, {
281→      detail: { tabId, title },
282→    });
283→    window.dispatchEvent(event);
284→  }
285→
286→  /**
287→   * Add a listener for tab title update events
288→   */
289→  static onUpdateTabTitle(handler: TabTitleUpdateEventHandler): () => void {
290→    if (!isInBrowser()) {
291→      return () => {};
292→    }
293→    const wrappedHandler = (e: Event) => {
294→      handler(e as CustomEvent<TabTitleUpdateEventDetail>);
295→    };
296→    window.addEventListener(TabManager.UPDATE_TAB_TITLE_EVENT, wrappedHandler);
297→    return () => window.removeEventListener(TabManager.UPDATE_TAB_TITLE_EVENT, wrappedHandler);
298→  }
299→}
