122→/**
123→ * Dashboard section component containing a header and a grid of panels.
124→ * Each section has its own ResponsiveGridLayout for independent drag/resize.
125→ */
126→export function DashboardSection({
127→  dashboardId,
128→  sectionIndex,
129→  group,
130→  panels,
131→  isCollapsed,
132→  onToggleCollapse,
133→  onSubComponentUpdated,
134→  globalPanelStartIndex,
135→  initialTimeSpan,
136→  initialFilterExpression,
137→  initialLoading,
138→  panelCollapseStates,
139→  onPanelCollapsedChange,
140→  onChartSelection,
141→  showEditControls = false,
142→  onRename,
143→  onDelete,
144→}: DashboardSectionProps) {
145→  const { width, mounted, containerRef } = useContainerWidth();
146→  const saveTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
147→
148→  // Track expand count to force grid remount after collapse/expand cycle
149→  const [expandCount, setExpandCount] = useState(0);
150→  const prevIsCollapsed = useRef(isCollapsed);
151→
152→  useEffect(() => {
153→    // When transitioning from collapsed to expanded, increment counter to force remount
154→    if (prevIsCollapsed.current && !isCollapsed) {
155→      setExpandCount(c => c + 1);
156→    }
157→    prevIsCollapsed.current = isCollapsed;
158→  }, [isCollapsed]);
159→
160→  // Generate default layouts
161→  const defaultLayouts = useMemo(
162→    () => generateLayoutsFromPanels(panels),
163→    [panels]
164→  );
165→
166→  // Load saved layouts or use defaults
167→  const [layouts, setLayouts] = useState<ResponsiveLayouts>(() => {
168→    const saved = loadSectionLayout(dashboardId, sectionIndex);
169→    return saved ?? defaultLayouts;
170→  });
171→
172→  // Update layouts when panels change
173→  useEffect(() => {
174→    const saved = loadSectionLayout(dashboardId, sectionIndex);
175→    setLayouts(saved ?? defaultLayouts);
176→  }, [dashboardId, sectionIndex, defaultLayouts]);
177→
178→  // Handle layout change with debounced save
179→  const onLayoutChange = useCallback(
180→    (_currentLayout: Layout, allLayouts: ResponsiveLayouts) => {
181→      setLayouts(allLayouts);
182→
183→      // Debounced save
184→      if (saveTimeoutRef.current) {
185→        clearTimeout(saveTimeoutRef.current);
186→      }
187→      saveTimeoutRef.current = setTimeout(() => {
188→        saveSectionLayout(dashboardId, sectionIndex, allLayouts);
189→      }, 500);
190→    },
191→    [dashboardId, sectionIndex]
192→  );
193→
194→  // Cleanup timeout on unmount
195→  useEffect(() => {
196→    return () => {
197→      if (saveTimeoutRef.current) {
198→        clearTimeout(saveTimeoutRef.current);
199→      }
200→    };
201→  }, []);
202→
203→  // Breakpoint configuration
204→  const breakpoints = { lg: 1024, md: 768, sm: 0 };
205→  const cols = { lg: 24, md: 6, sm: 1 };
206→
207→  const sectionTitle = group?.title ?? "Ungrouped";
208→
209→  // Don't render header for ungrouped section if there's only ungrouped panels
210→  const showHeader = group !== null;
211→
212→  console.log('[DashboardSection] Render - sectionIndex:', sectionIndex, 'isCollapsed:', isCollapsed, 'panels.length:', panels.length, 'showHeader:', showHeader, 'mounted:', mounted, 'width:', width);
213→
214→  return (
215→    <div className="w-full">
216→      {showHeader && (
217→        <SectionHeader
218→          title={sectionTitle}
219→          isCollapsed={isCollapsed}
220→          onToggleCollapse={onToggleCollapse}
221→          showEditControls={showEditControls}
222→          onRename={onRename}
223→          onDelete={onDelete}
224→        />
225→      )}
226→
227→      {/* Always render container so useContainerWidth hook can measure width */}
228→      {panels.length > 0 && (
229→        <div
230→          ref={containerRef}
231→          className="w-full"
232→          style={isCollapsed ? { height: 0, overflow: 'hidden', visibility: 'hidden' } : undefined}
233→        >
234→          {!isCollapsed && mounted && width > 0 && (
235→            <ResponsiveGridLayout
236→              key={`grid-${sectionIndex}-${expandCount}`}
237→              className="layout"
238→              width={width}
239→              layouts={layouts}
240→              breakpoints={breakpoints}
241→              cols={cols}
242→              rowHeight={36}
243→              margin={[8, 8]}
244→              containerPadding={[0, 0]}
245→              onLayoutChange={onLayoutChange}
246→              dragConfig={{ enabled: true, bounded: false, handle: ".dashboard-drag-handle", threshold: 3 }}
247→              compactor={verticalCompactor}
248→            >
249→              {panels.map((panel, localIndex) => {
250→                const globalIndex = globalPanelStartIndex + localIndex;
251→                const isPanelCollapsed = panelCollapseStates.get(globalIndex) ?? panel.collapsed ?? false;
252→
253→                return (
254→                  <div key={`panel-${localIndex}`} className="h-full">
255→                    <div className={cn("w-full h-full", isPanelCollapsed && "h-auto")}>
256→                      <DashboardVisualizationPanel
257→                        descriptor={panel}
258→                        initialTimeSpan={initialTimeSpan}
259→                        initialFilterExpression={initialFilterExpression}
260→                        initialLoading={initialLoading}
261→                        ref={(el) => onSubComponentUpdated(el, globalIndex)}
262→                        onCollapsedChange={(collapsed) => onPanelCollapsedChange(globalIndex, collapsed)}
263→                        onChartSelection={onChartSelection}
264→                      />
265→                    </div>
266→                  </div>
267→                );
268→              })}
269→            </ResponsiveGridLayout>
270→          )}
271→        </div>
272→      )}
273→
274→      {!isCollapsed && panels.length === 0 && showEditControls && (
275→        <div className="px-4 py-8 text-center text-sm text-muted-foreground border-b">
276→          No panels in this section. Add panels to get started.
277→        </div>
278→      )}
279→    </div>
280→  );
281→}
