405→        // Tabs are in insertion order, so we just use them as-is
406→        const currentIndex = prevTabs.findIndex((t) => t.id === tabId);
407→        if (currentIndex === -1) {
408→          return prevTabs;
409→        }
410→
411→        // Keep tabs up to and including the current tab
412→        const tabsToKeep = prevTabs.slice(0, currentIndex + 1);
413→        const closedTabIds = prevTabs.slice(currentIndex + 1).map((t) => t.id);
414→
415→        // If the active tab is in the closed tabs, switch to the clicked tab
416→        if (closedTabIds.includes(activeTab)) {
417→          setActiveTab(tabId);
418→        }
419→
420→        return tabsToKeep;
421→      });
422→    },
423→    [activeTab]
424→  );
425→
426→  // Handle closing all tabs except the clicked one
427→  const handleCloseOthers = useCallback(
428→    (tabId: string) => {
429→      setTabs((prevTabs) => {
430→        const newTabs = prevTabs.filter((t) => t.id === tabId);
431→
432→        // If the active tab was closed, switch to the clicked tab
433→        if (activeTab !== tabId && !newTabs.some((t) => t.id === activeTab)) {
434→          setActiveTab(tabId);
435→        }
436→
437→        return newTabs;
438→      });
439→    },
