458→  // Only updates state when values actually change to prevent unnecessary re-renders
459→  const checkScrollPosition = useCallback(() => {
460→    const container = tabsScrollContainerRef.current;
461→    if (!container) return;
462→
463→    const { scrollLeft, scrollWidth, clientWidth } = container;
464→    const newCanScrollLeft = scrollLeft > 0;
465→    const newCanScrollRight = scrollLeft < scrollWidth - clientWidth - 1;
466→
467→    // Only update state if values actually changed
