 60→function HoverCardSidebarMenuItem({
 61→  icon,
 62→  description,
 63→  content,
 64→  contentClassName,
 65→  align = "start",
 66→}: {
 67→  icon: React.ReactNode;
 68→  description?: string;
 69→  content: (isOpen: boolean, onClose: () => void) => React.ReactNode;
 70→  contentClassName?: string;
 71→  align?: "start" | "center" | "end";
 72→}) {
 73→  const [isOpen, setIsOpen] = useState(false);
 74→  const isClickingRef = React.useRef(false);
 75→
 76→  const onOpenChange = useCallback((newState: boolean) => {
 77→    // This callback is invoked by HoverCard when it wants to change the open state.
 78→    // We add this callback because if user click the trigger, the hover card will close --> open --> close.
 79→    // We add this for better UX.
 80→    //
 81→    // The HoverCard will try to close when:
 82→    // 1. Mouse leaves both the trigger and content
 83→    // 2. User clicks on the trigger (which we want to prevent)
 84→    //
 85→    // When user clicks the trigger while the card is open:
 86→    // - handlePointerDown sets isClickingRef.current = true
 87→    // - HoverCard detects the click and calls onOpenChange(false)
 88→    // - We intercept this close request here and ignore it
 89→    // - Reset the flag so future legitimate close requests work
 90→    if (newState === false && isClickingRef.current) {
 91→      isClickingRef.current = false;
 92→      return; // Ignore the close request - keep the card open
 93→    }
 94→
 95→    // For all other cases (hover in/out), update the state normally
 96→    setIsOpen(newState);
 97→  }, []);
 98→
 99→  const onMenuItemPointerDown = useCallback(() => {
100→    // When user clicks the trigger button while the hover card is already open,
101→    // we set a flag so that onOpenChange can ignore the subsequent close request.
102→    // This prevents the card from closing when clicking the trigger.
103→    if (isOpen) {
104→      isClickingRef.current = true;
105→    }
106→  }, [isOpen]);
107→
108→  const onClose = useCallback(() => {
109→    setIsOpen(false);
110→  }, []);
111→
112→  return (
113→    <SidebarMenuItem>
114→      <HoverCard openDelay={200} open={isOpen} onOpenChange={onOpenChange}>
115→        <HoverCardTrigger asChild>
116→          <SidebarMenuButton size="default" onPointerDown={onMenuItemPointerDown}>
117→            {icon}
118→          </SidebarMenuButton>
119→        </HoverCardTrigger>
120→        <HoverCardContent side="right" align={align} className={contentClassName}>
121→          {description && <p className="text-xs text-muted-foreground mb-2 px-1">{description}</p>}
122→          {content(isOpen, onClose)}
123→        </HoverCardContent>
124→      </HoverCard>
125→    </SidebarMenuItem>
126→  );
127→}
