129→function ConnectionManageSidebarMenuItem() {
130→  const { isMobile } = useSidebar();
131→  const { connection } = useConnection();
132→  const [open, setOpen] = useState(false);
133→  const [tooltipAllowed, setTooltipAllowed] = useState(true);
134→  const tooltipDelayRef = React.useRef<ReturnType<typeof setTimeout> | null>(null);
135→
136→  // Suppress the sidebar button tooltip while the popover is open and briefly after it closes.
137→  useEffect(() => {
138→    if (open) {
139→      if (tooltipDelayRef.current) {
140→        clearTimeout(tooltipDelayRef.current);
141→        tooltipDelayRef.current = null;
142→      }
143→      setTooltipAllowed(false);
144→    } else {
145→      tooltipDelayRef.current = setTimeout(() => {
146→        setTooltipAllowed(true);
147→        tooltipDelayRef.current = null;
148→      }, 400);
149→    }
150→    return () => {
151→      if (tooltipDelayRef.current) clearTimeout(tooltipDelayRef.current);
152→    };
153→  }, [open]);
154→
155→  const triggerButton = (
156→    <SidebarMenuButton
157→      size="default"
158→      tooltip={
159→        tooltipAllowed
160→          ? {
161→              children: "Switch connection",
162→              className: "bg-primary text-primary-foreground text-xs px-2 py-1 border-0 rounded-sm",
163→            }
164→          : undefined
165→      }
166→      onClick={isMobile ? undefined : () => setOpen((s) => !s)}
167→    >
168→      <Database className="h-5 w-5" />
169→      <span>Switch connection</span>
170→    </SidebarMenuButton>
171→  );
172→
173→  if (isMobile) {
174→    return (
175→      <SidebarMenuItem>
176→        <ConnectionSelectorDialog
177→          trigger={triggerButton}
178→          defaultConnectionName={connection?.name ?? null}
179→        />
180→      </SidebarMenuItem>
181→    );
182→  }
183→
184→  return (
185→    <Popover open={open} onOpenChange={setOpen}>
186→      <PopoverTrigger asChild>{triggerButton}</PopoverTrigger>
187→      <PopoverContent side="right" align="start" className="!w-auto !max-w-none p-0 shadow-lg">
188→        <ConnectionSelector isOpen={open} onClose={() => setOpen(false)} />
189→      </PopoverContent>
190→    </Popover>
191→  );
192→}
